"""Funciones auxiliares para preparar los datos del experimento.Este módulo se encarga de:- convertir un DataFrame de features en matrices X e y,- dividir el dataset en:    1) conjunto inicial de entrenamiento global (seed),    2) pool de datos para clientes móviles,    3) conjunto de test independiente."""from __future__ import annotationsimport numpy as npimport pandas as pdfrom sklearn.model_selection import train_test_splitdef df_to_xy(df: pd.DataFrame) -> tuple[np.ndarray, np.ndarray]:    """    Convierte un DataFrame de features en una matriz de entrada X    y un vector de etiquetas y.    El DataFrame debe contener:    - una columna 'dx' con la clase,    - varias columnas de features con prefijo 'f'.    Parameters    ----------    df : pd.DataFrame        DataFrame con las features y la etiqueta de clase.    Returns    -------    tuple[np.ndarray, np.ndarray]        X : matriz de características en formato float64        y : vector de etiquetas en formato string    """    feature_cols = [col for col in df.columns if col.startswith("f")]    X = df[feature_cols].to_numpy(dtype=np.float64)    y = df["dx"].astype(str).to_numpy()    return X, ydef make_train_test_split(    df: pd.DataFrame,    seed_size: int,    test_size: float,    random_state: int,) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:    """    Divide el dataset completo en tres subconjuntos:    1. df_seed:       conjunto usado para entrenar el modelo global inicial.    2. df_pool:       conjunto de imágenes que no se usan en el entrenamiento inicial       y que servirán como fuente de datos para los clientes móviles.    3. df_test:       conjunto independiente reservado para evaluación.    La división es estratificada respecto a la clase 'dx'.    Parameters    ----------    df : pd.DataFrame        Dataset completo con features y etiquetas.    seed_size : int        Número de muestras que se usarán para el entrenamiento inicial.    test_size : float        Proporción del dataset reservada para test.    random_state : int        Semilla aleatoria para reproducibilidad.    Returns    -------    tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]        df_seed, df_pool, df_test    Raises    ------    ValueError        Si no hay suficientes datos para construir las tres particiones.    """    if len(df) < seed_size + 50:        raise ValueError(            "No hay suficientes imágenes válidas para construir "            "seed, pool y test."        )    # Primera división: separar test del resto    df_train_pool, df_test = train_test_split(        df,        test_size=test_size,        stratify=df["dx"],        random_state=random_state,    )    if seed_size >= len(df_train_pool):        raise ValueError(            "seed_size es demasiado grande respecto al número de muestras "            "disponibles tras separar el conjunto de test."        )    # Segunda división: separar seed inicial del pool federado    df_seed, df_pool = train_test_split(        df_train_pool,        train_size=seed_size,        stratify=df_train_pool["dx"],        random_state=random_state,    )    return (        df_seed.reset_index(drop=True),        df_pool.reset_index(drop=True),        df_test.reset_index(drop=True),    )